mapper.select:
/* selectOmr1List */ SELECT CONCAT(WK.COMPKEY, WK.OWNERKY, WK.SKUMKEY) as ROWKEY ,WK.COMPKEY, WK.STOCKKY, WK.WAREKEY, MW.WHNAMLC as WAREKEY1, WK.AREAKEY ,WK.ZONEKEY, WK.LOCAKEY, WK.SUBSECT, WK.TRUNTYP ,WK.TRUNPID, WK.LOTNMKY, WK.OWNERKY ,MO.OWNAMLC as OWNERKY1, MS.SKUMKEY ,MS.SKUDESC, WK.VENDKEY, WK.SIRBCOD, WK.STOTQTY ,WK.SALLQTY, WK.SINBQTY, WK.SOUBQTY, WK.SBLOQTY ,MS.SUOMKEY, WK.PRODDAT, WK.SHELIFE, WK.EXPIDAT ,WK.RCVFRDT, WK.LOTFRKY, WK.LOTAT01, date_format(WK.RCVDCDT, '%Y-%m-%d') as RCVDCDT ,WK.LOTAT02, WK.LOTAT03, WK.LOTAT04, WK.LOTAT05 ,WK.LOTAT06, WK.LOTAT07, WK.LOTAT08, WK.LOTAT09 ,WK.LOTAT10, WK.LOTAT11, WK.LOTAT12, WK.LOTAT13 ,WK.LOTAT14, WK.LOTAT15, WK.LOTAT16, WK.LOTAT17 ,WK.LOTAT18, WK.LOTAT19, WK.LOTAT20, MC.COMCDTX as STKSTAT1 ,WK.BLOCKID, WK.PHYSROW, WK.PHYSSEC, WK.PHYSFLO ,WK.RCVDCKY, WK.RCVDCIT, WK.TASKOKY, WK.TASKOIT ,WK.ADJSOKY, WK.ADJSOIT, WK.PHYSOKY, WK.PHYSOIT ,WK.STORFKY, WK.DOCCATE, WK.DOCTYPE, WK.CREDATE ,WK.CRETIME, fn_sy_usernam(WK.COMPKEY, WK.CREUSER) as CREUSER, WK.LMODATE, WK.LMOTIME ,fn_sy_usernam(WK.COMPKEY, WK.LMOUSER) as LMOUSER, WK.INDIBZL, WK.INDIARC, WK.UPDTCHK ,SKUAT03, WK.STKSTAT, MA.AREANAM , MZ.ZONENAM, ML.LOCANAM FROM WSTKKY WK INNER JOIN MSKUWC MS ON WK.COMPKEY = MS.COMPKEY AND WK.WAREKEY = MS.WAREKEY AND WK.OWNERKY = MS.OWNERKY AND WK.SKUMKEY = MS.SKUMKEY INNER JOIN MWARMA MW ON WK.COMPKEY = MW.COMPKEY AND WK.WAREKEY = MW.WAREKEY INNER JOIN MOWRMA MO ON WK.COMPKEY = MO.COMPKEY AND WK.OWNERKY = MO.OWNERKY INNER JOIN V_MCODEM MC ON WK.COMPKEY = MC.COMPKEY AND WK.STKSTAT = MC.COMCDVL AND MC.COMCDKY = 'STKSTAT' INNER JOIN MAREMA MA ON WK.COMPKEY = MA.COMPKEY AND WK.WAREKEY = MA.WAREKEY AND WK.AREAKEY = MA.AREAKEY INNER JOIN MZONMA MZ ON WK.COMPKEY = MZ.COMPKEY AND WK.WAREKEY = MZ.WAREKEY AND WK.AREAKEY = MZ.AREAKEY AND WK.ZONEKEY = MZ.ZONEKEY INNER JOIN MLOCMA ML ON WK.COMPKEY = ML.COMPKEY AND WK.WAREKEY = ML.WAREKEY AND WK.AREAKEY = ML.AREAKEY AND WK.ZONEKEY = ML.ZONEKEY AND WK.LOCAKEY = ML.LOCAKEY WHERE WK.COMPKEY = #{compkey} AND WK.STOTQTY > 0 AND WK.AREAKEY = 'STG'
and WK.WAREKEY = #{warekey}
and WK.OWNERKY = #{ownerky}
AND UPPER(WK.SKUMKEY) LIKE CONCAT('%', UPPER(#{skumkey}), '%')
AND UPPER(WK.SKUDESC) LIKE CONCAT('%', UPPER(#{skudesc}), '%')
ORDER BY WK.RCVDCDT DESC

/* selectOmr01SkuList */
select DISTINCT skumkey,skudesc from WSTKKY
WHERE COMPKEY = #{compkey}
AND OWNERKY = #{ownerky}

	and UPPER(WAREKEY) = #{warekey}


	and UPPER(OWNERKY) = #{ownerky}


	and UPPER(SKUMKEY) = #{skumkey}


	and UPPER(SKUDESC) = #{skudesc}

/* selectMordmaList */
select COOCATE 
	 , COOTYPE as COMBOVL
	 , OCOCTNM
	 , COOTYNM as COMBONM
  from MORDMA

  	and COMPKEY = #{compkey}

		and WAREKEY = #{warekey}


		and COOCATE = #{coocate}


		and COOTYPE = #{cootype}


		and COOTYPE IN

			#{item}




			and COUSEYN = #{couseyn}


			and COUSEYN = 'Y'



group by COOTYPE, COOTYNM
order by COOTYPE, COOTYNM

/* selectOmr03List */ SELECT O.COMPKEY, O.OERETKY, O.OERETIT, O.OERETIT, O.OEINSST, O.RSNCODE, O.RSNDESC, O.WAREKEY, O.DOCCATE, O.DOCTYPE, O.STOCKKY, O.AREAKEY, O.ZONEKEY, O.LOCAKEY, O.OWNERKY, O.SKUMKEY, O.SKUDESC, O.SUOMKEY, O.RTCFQTY, O.RTODQTY, O.PTNRKEY, O.CRETIME, fn_sy_usernam(O.COMPKEY, O.CREUSER) as CREUSER, O.STOTQTY, O.OEINSST, MW.WHNAMLC as WAREKEY1, MO.OWNAMLC as OWNERKY1, O.LMODATE, O.LMOTIME, O.LMOUSER, O.UPDTCHK, O.SUBSECT, O.TRUNTYP, O.TRUNPID, O.LOTNMKY, O.SALLQTY, O.SINBQTY, O.SOUBQTY, O.SBLOQTY, O.RETAT01, O.RETAT02, O.RETAT03, MA.AREANAM , MZ.ZONENAM, ML.LOCANAM, date_format(O.CREDATE, '%Y-%m-%d')as CREDATE, date_format(O.OEINSDT, '%Y-%m-%d')as OEINSDT, date_format(str_to_date(O.OEINSTM, '%H%i%s'), '%H:%i:%s') as OEINSTM, M.COMCDVL as STKSTAT1, M.COMCDTX, M.COMKYTX FROM OERETI O INNER JOIN V_MCODEM M ON O.OEINSST = M.COMCDVL AND M.COMPKEY=O.COMPKEY AND M.COMCDKY='OEINSST' INNER JOIN MWARMA MW ON O.COMPKEY = MW.COMPKEY AND O.WAREKEY = MW.WAREKEY INNER JOIN MOWRMA MO ON O.COMPKEY = MO.COMPKEY AND O.OWNERKY = MO.OWNERKY INNER JOIN MAREMA MA ON O.COMPKEY = MA.COMPKEY AND O.AREAKEY = MA.AREAKEY AND O.WAREKEY = MA.WAREKEY INNER JOIN MZONMA MZ ON O.COMPKEY = MZ.COMPKEY AND O.WAREKEY = MZ.WAREKEY AND O.AREAKEY = MZ.AREAKEY AND O.ZONEKEY = MZ.ZONEKEY INNER JOIN MLOCMA ML ON O.COMPKEY = ML.COMPKEY AND O.WAREKEY = ML.WAREKEY AND O.AREAKEY = ML.AREAKEY AND O.ZONEKEY = ML.ZONEKEY AND O.LOCAKEY = ML.LOCAKEY WHERE O.COMPKEY = #{compkey} AND (O.doctype='330' OR O.doctype='340') AND O.doccate='300' AND (O.OEINSST = 'NEW' OR O.OEINSST = 'CMP')
and O.OEINSDT >= replace(#{oeinsdtFrom},'-','')
and O.OEINSDT <= replace(#{oeinsdtTo},'-','')
and O.OEINSDT between replace(#{oeinsdtFrom},'-','') and replace(#{oeinsdtTo},'-','')
AND O.WAREKEY = #{warekey}
AND O.OWNERKY = #{ownerky}
AND UPPER(O.SKUMKEY) LIKE CONCAT('%', UPPER(#{skumkey}), '%')
AND UPPER(O.SKUDESC) LIKE CONCAT('%', UPPER(#{skudesc}), '%')
AND UPPER(O.OEINSST) LIKE CONCAT('%', UPPER(#{oeinsst}), '%')
AND (
UPPER(O.RSNCODE) LIKE CONCAT('%', UPPER(#{code}), '%')
)
AND DATE_FORMAT(OEINSDT, '%Y%m%d') = #{oeinsdt}
ORDER BY O.OERETKY DESC

/* selectOmr04List */ SELECT O.COMPKEY, O.OERETKY, O.OERETIT, O.OERETIT, O.RECRSCD, O.RECRSNM, O.OEINSST, O.RSNCODE, O.RSNDESC, O.WAREKEY, O.DOCCATE, O.DOCTYPE, O.STOCKKY, O.AREAKEY, O.ZONEKEY, O.LOCAKEY, O.OWNERKY, O.SKUMKEY, O.SKUDESC, O.STKSTAT, O.SUOMKEY, O.RTODQTY, O.PTNRKEY, O.CRETIME, fn_sy_usernam(O.COMPKEY, O.CREUSER) as CREUSER, O.STOTQTY, O.OEINSST, MW.WHNAMLC as WAREKEY1, MO.OWNAMLC as OWNERKY1, O.UPDTCHK, O.LMOTIME, fn_sy_usernam(O.COMPKEY, O.LMOUSER) as LMOUSER, MA.AREANAM , MZ.ZONENAM, ML.LOCANAM, date_format(O.CREDATE, '%Y-%m-%d')as CREDATE, date_format(O.OEINSDT, '%Y-%m-%d')as OEINSDT, date_format(O.LMODATE, '%Y-%m-%d')as LMODATE, date_format(str_to_date(O.OEINSTM, '%H%i%s'), '%H:%i:%s') as OEINSTM, M.COMCDTX as STKSTAT1 FROM OERETI O INNER JOIN V_MCODEM M ON O.STKSTAT = M.COMCDVL AND M.COMPKEY=O.COMPKEY AND M.COMCDKY='STKSTAT' INNER JOIN MWARMA MW ON O.COMPKEY = MW.COMPKEY AND O.WAREKEY = MW.WAREKEY INNER JOIN MOWRMA MO ON O.COMPKEY = MO.COMPKEY AND O.OWNERKY = MO.OWNERKY INNER JOIN MAREMA MA ON O.COMPKEY = MA.COMPKEY AND O.AREAKEY = MA.AREAKEY AND O.WAREKEY = MA.WAREKEY INNER JOIN MZONMA MZ ON O.COMPKEY = MZ.COMPKEY AND O.WAREKEY = MZ.WAREKEY AND O.AREAKEY = MZ.AREAKEY AND O.ZONEKEY = MZ.ZONEKEY INNER JOIN MLOCMA ML ON O.COMPKEY = ML.COMPKEY AND O.WAREKEY = ML.WAREKEY AND O.AREAKEY = ML.AREAKEY AND O.ZONEKEY = ML.ZONEKEY AND O.LOCAKEY = ML.LOCAKEY WHERE O.COMPKEY = #{compkey} AND (O.doctype='330' OR O.doctype='340') AND O.doccate='300' AND (O.OEINSST = 'CAN')
and O.OEINSDT >= replace(#{oeinsdtFrom},'-','')
and O.OEINSDT <= replace(#{oeinsdtTo},'-','')
and O.OEINSDT between replace(#{oeinsdtFrom},'-','') and replace(#{oeinsdtTo},'-','')
AND O.WAREKEY = #{warekey}
AND O.OWNERKY = #{ownerky}
AND UPPER(O.SKUMKEY) LIKE CONCAT('%', UPPER(#{skumkey}), '%')
AND UPPER(O.SKUDESC) LIKE CONCAT('%', UPPER(#{skudesc}), '%')
AND UPPER(O.RECRSCD) LIKE CONCAT('%', UPPER(#{recrsnm}), '%')
AND DATE_FORMAT(OEINSDT, '%Y%m%d') = #{oeinsdt}
ORDER BY O.OERETKY DESC

/* selectOmr05List */ SELECT CONCAT(O.COMPKEY, O.OWNERKY, O.SKUMKEY) as ROWKEY, O.COMPKEY, O.OERETKY, O.OERETIT, O.OERETIT, O.OEINSST, O.RSNCODE, O.RSNDESC, O.WAREKEY, O.DOCCATE, O.DOCTYPE, O.STOCKKY, O.AREAKEY, O.ZONEKEY, O.LOCAKEY, O.OWNERKY, O.SKUMKEY, O.SKUDESC, O.STKSTAT, O.SUOMKEY, O.RTODQTY, O.PTNRKEY, fn_sy_usernam(O.COMPKEY, O.CREUSER) as CREUSER, O.STOTQTY, M.COMCDTX, MW.WHNAMLC as WAREKEY1, MO.OWNAMLC as OWNERKY1, MA.AREANAM , MZ.ZONENAM, ML.LOCANAM,O.CRETIME, date_format(O.CREDATE, '%Y-%m-%d')as CREDATE, date_format(O.OEINSDT, '%Y-%m-%d')as OEINSDT, date_format(str_to_date(O.OEINSTM, '%H%i%s'), '%H:%i:%s') as OEINSTM FROM OERETI O INNER JOIN V_MCODEM M ON O.STKSTAT = M.COMCDVL AND M.COMPKEY= #{compkey} AND M.COMCDKY='STKSTAT' INNER JOIN MWARMA MW ON O.COMPKEY = MW.COMPKEY AND O.WAREKEY = MW.WAREKEY INNER JOIN MOWRMA MO ON O.COMPKEY = MO.COMPKEY AND O.OWNERKY = MO.OWNERKY INNER JOIN MAREMA MA ON O.COMPKEY = MA.COMPKEY AND O.AREAKEY = MA.AREAKEY AND O.WAREKEY = MA.WAREKEY INNER JOIN MZONMA MZ ON O.COMPKEY = MZ.COMPKEY AND O.WAREKEY = MZ.WAREKEY AND O.AREAKEY = MZ.AREAKEY AND O.ZONEKEY = MZ.ZONEKEY INNER JOIN MLOCMA ML ON O.COMPKEY = ML.COMPKEY AND O.WAREKEY = ML.WAREKEY AND O.AREAKEY = ML.AREAKEY AND O.ZONEKEY = ML.ZONEKEY AND O.LOCAKEY = ML.LOCAKEY WHERE O.COMPKEY = #{compkey} AND (O.doctype='330' OR O.doctype='340') AND O.doccate='300' AND O.OEINSST = 'NEW'
and O.OEINSDT >= replace(#{oeinsdtFrom},'-','')
and O.OEINSDT <= replace(#{oeinsdtTo},'-','')
and O.OEINSDT between replace(#{oeinsdtFrom},'-','') and replace(#{oeinsdtTo},'-','')
AND O.WAREKEY = #{warekey}
AND O.OWNERKY = #{ownerky}
AND UPPER(O.SKUMKEY) LIKE CONCAT('%', UPPER(#{skumkey}), '%')
AND UPPER(O.SKUDESC) LIKE CONCAT('%', UPPER(#{skudesc}), '%')
AND DATE_FORMAT(O.OEINSDT, '%Y%m%d') = #{oeinsdt}
ORDER BY O.OERETKY DESC

mapper.insert:
/* insertOcosal */ insert into OCOSAL( COMPKEY, COOUTKY, COOUTIT, DOCCATE, DOCTYPE, POSTDAT, SALDATE, SALTIME, TOWARKY, CUSTKEY, DESTKEY, OWNERKY, SKUSKEY, SKUMKEY, SKUDESC, SOITQTY, RGITQTY, SHCFQTY, SUOMKEY, DCTCTYP,SALSTAT, SAATN01, SAATN02, SAATN03, SAATN04, SAATN05, SAATC01, SAATC02, SAATC03,SAATC04, SAATC05, CREDATE, CRETIME , CREUSER , LMODATE , LMOTIME, LMOUSER, SAATC06, SAATC07, SAATC08, SAATC09, SAATC10, SALRQDT,SALMEMO
) values ( #{userData.compkey}, #{cooutky}, FN_OM_COOUTIT(#{userData.compkey}, #{cooutky}), #{coocate}, #{cootype}, DATE_FORMAT(#{postdat},'%Y%m%d'), DATE_FORMAT(NOW(),'%Y%m%d'), DATE_FORMAT(NOW(),'%H%i%s'), #{warekey}, #{custkey}, #{destkey}, #{ownerky}, #{skuskey}, #{skumkey}, #{skudesc}, #{soitqty}, #{rgitqty}, #{shcfqty}, #{suomkey}, #{dctctyp}, #{salstat}, #{saatn01}, #{saatn02}, #{saatn03}, #{saatn04}, #{saatn05}, IFNULL(#{saatc01}, ''), IFNULL(#{saatc02}, ''), IFNULL(#{saatc03}, ''),IFNULL(#{saatc04}, ''), IFNULL(#{saatc05}, ''), date_format(NOW(),'%Y%m%d'), date_format(NOW(),'%H%i%s'), #{userData.useract} , date_format(NOW(),'%Y%m%d'), date_format(NOW(),'%H%i%s'), #{userData.useract}, IFNULL(#{saatc06}, #{cooutky}), IFNULL(#{saatc07}, ''),IFNULL(#{saatc08}, ''),IFNULL(#{saatc09}, ''),IFNULL(#{saatc10}, ''), DATE_FORMAT(#{postdat},'%Y%m%d'),upper(ifnull(#{salmemo},''))
)
